+        .collect();
+
+    if actual_columns.len() != EXPECTED_ISSUE_COLUMN_ORDER.len() {
+        return false;
+    }
+
+    actual_columns
+        .iter()
+        .zip(EXPECTED_ISSUE_COLUMN_ORDER.iter())
+        .all(|(actual, expected)| actual == expected)
